import React, { useState } from 'react';
import { useNavigate, useParams, useSearchParams } from 'react-router-dom';
import { Input, Select, dispatchAppToast } from '@linm-soft/common-components';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useAppDispatch } from '../../../store/hooks';
import { useDdmhPermissions } from '../../../hooks/useDdmhPermissions';
import { ddmhPageLabels } from '../../../constants/ddmhPageLabels';
import { purchasingService } from '../../../services/mh/purchasingService';
import { wmsService } from '../../../services/kho/wmsService';
import type { OrderLineDto } from '../../../services/mh/models';
import type { PartnerDto } from '../../../services/kho/models';
import { MH_PATHS } from '../../../appPaths';
import { DocumentFormHeader } from '../../../components/layout';
import {
  MaterialLinesGridActions,
  useMaterialLinesSelection,
  VoucherDocumentFormShell,
} from '../../../components/form';
import { LineMaterialSearchCell, MaterialLineTableHeaders } from '../../../components/search';
import { formatMoneyVnd } from '../../../utils/formatters';
import df from '../../../styles/documentForm.module.css';

const emptyLine = (): OrderLineDto => ({ materialCode: '', unitCode: '', quantity: 1, unitPrice: 0, amount: 0 });

const DdmhFormPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { canWrite } = useDdmhPermissions();
  const navigate = useNavigate();
  const { id: routeId } = useParams<{ id: string }>();
  const [searchParams] = useSearchParams();
  const editId = routeId && routeId !== 'them' ? routeId : searchParams.get('editId') ?? undefined;
  const isEdit = Boolean(editId);
  const isNew = !isEdit;
  const [orderDate, setOrderDate] = useState(() => new Date().toISOString().slice(0, 10));
  const [supplierId, setSupplierId] = useState('');
  const [description, setDescription] = useState('');
  const [exchangeRate, setExchangeRate] = useState(1);
  const [lines, setLines] = useState<OrderLineDto[]>([emptyLine()]);
  const [suppliers, setSuppliers] = useState<PartnerDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  const { copyLine, lineRowProps } = useMaterialLinesSelection(lines, setLines);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      wmsService.getPartners('Supplier').then(s => { if (!cancelled) setSuppliers(s); }).catch(err => {
        if (!cancelled) {
          dispatchAppToast(dispatch, {
            message: getApiErrorMessage(err, ddmhPageLabels.loadError),
            type: 'error',
          });
        }
      });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [dispatch]);

  React.useEffect(() => {
    if (!editId) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      purchasingService.getOrder(editId)
        .then(o => {
          if (cancelled) return;
          setOrderDate(o.orderDate?.slice(0, 10) ?? '');
          setSupplierId(o.supplierId);
          setDescription(o.description ?? '');
          setExchangeRate(o.exchangeRate);
          setLines(o.lines?.length ? o.lines : [emptyLine()]);
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, ddmhPageLabels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [editId, dispatch]);

  const supplierOptions = [{ value: '', label: '— Chọn NCC —' }, ...suppliers.map(s => ({ value: s.id, label: s.name }))];
  const updateLine = (idx: number, patch: Partial<OrderLineDto>) => {
    setLines(prev => prev.map((l, i) => {
      if (i !== idx) return l;
      const next = { ...l, ...patch };
      next.amount = (next.quantity || 0) * (next.unitPrice || 0);
      return next;
    }));
  };
  const addLine = () => setLines(prev => [...prev, emptyLine()]);
  const removeLine = (idx: number) => {
    if (lines.length <= 1) {
      dispatchAppToast(dispatch, { message: ddmhPageLabels.minLineWarning, type: 'warning' });
      return;
    }
    setLines(prev => prev.filter((_, i) => i !== idx));
  };
  const totalAmount = lines.reduce((s, l) => s + (l.amount || 0), 0);

  const handleSave = async () => {
    if (!canWrite) return;
    if (!supplierId) {
      dispatchAppToast(dispatch, { message: ddmhPageLabels.supplierWarning, type: 'warning' });
      return;
    }
    if (!lines.some(l => l.materialCode.trim())) {
      dispatchAppToast(dispatch, { message: ddmhPageLabels.materialLineWarning, type: 'warning' });
      return;
    }
    setSaving(true);
    try {
      const payload = {
        orderDate: new Date(orderDate).toISOString(),
        supplierId,
        description: description || undefined,
        exchangeRate,
        lines: lines.filter(l => l.materialCode.trim()),
      };
      if (isEdit && editId) {
        await purchasingService.updateOrder(editId, payload);
        dispatchAppToast(dispatch, { message: ddmhPageLabels.updateSuccess, type: 'success' });
        navigate(MH_PATHS.ddmhDetail(editId));
      } else {
        const created = await purchasingService.createOrder(payload);
        dispatchAppToast(dispatch, { message: ddmhPageLabels.createSuccess, type: 'success' });
        navigate(MH_PATHS.ddmhDetail(created.id));
      }
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, ddmhPageLabels.saveError),
        type: 'error',
      });
    } finally { setSaving(false); }
  };

  const backPath = isEdit && editId ? MH_PATHS.ddmhDetail(editId) : MH_PATHS.ddmh;
  if (loading) return <div className={df.loading} data-testid="erp-mh-ddmh-form-loading">Đang tải...</div>;

  return (
    <VoucherDocumentFormShell
      testId="erp-mh-ddmh-form"
      header={(
        <DocumentFormHeader
          onBack={() => navigate(backPath)}
          title={isEdit ? 'Sửa đơn đặt hàng' : 'Tạo đơn đặt hàng'}
          isNew={isNew}
          saving={saving}
          saveLabel="Tạo đơn"
          saveEditLabel="Lưu thay đổi"
          onSave={canWrite ? handleSave : undefined}
          isReadOnly={!canWrite}
        />
      )}
      footer={(
        <div className={df.footer}>
          <div />
          <div className={df.totalBlock}>
            <span className={df.totalLabel}>Tổng tiền:</span>
            <span className={df.totalValue}>{formatMoneyVnd(totalAmount)}</span>
          </div>
        </div>
      )}
    >
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin chung</h2>
        <div className={df.row4}>
          <div className={df.field}><label className={df.label}>Ngày đơn</label><Input type="date" value={orderDate} onChange={e => setOrderDate(e.target.value)} disabled={!canWrite} /></div>
          <div className={df.field}><label className={df.label}>Nhà cung cấp</label><Select value={supplierId} onChange={e => setSupplierId(e.target.value)} options={supplierOptions} disabled={!canWrite} /></div>
          <div className={df.field}><label className={df.label}>Tỷ giá</label><Input type="number" value={String(exchangeRate)} onChange={e => setExchangeRate(Number(e.target.value))} disabled={!canWrite} /></div>
          <div className={df.field}><label className={df.label}>Mô tả</label><Input value={description} onChange={e => setDescription(e.target.value)} disabled={!canWrite} /></div>
        </div>
      </div>
      <div className={[df.section, df.linesSection].join(' ')}>
        <h2 className={df.sectionTitle}>Chi tiết hàng</h2>
        <div className={df.tableWrapper}>
          <table className={[df.linesTable, df.linesTableStacked].join(' ')}>
            <thead><tr><MaterialLineTableHeaders /><th>ĐVT</th><th className={df.thAmount}>SL</th><th className={df.thAmount}>Đơn giá</th><th className={df.thAmount}>Thành tiền</th><th className={df.thDel} /></tr></thead>
            <tbody>
              {lines.map((line, idx) => (
                <tr key={idx} {...lineRowProps(idx)}>
                  <LineMaterialSearchCell
                    materialCode={line.materialCode}
                    materialName={line.materialName ?? ''}
                    disabled={!canWrite}
                    onSelect={m => updateLine(idx, {
                      materialCode: m.code,
                      materialName: m.name,
                      unitCode: m.unitCode ?? line.unitCode,
                    })}
                    onClear={() => updateLine(idx, { materialCode: '', materialName: '' })}
                  />
                  <td data-label="ĐVT"><Input value={line.unitCode} onChange={e => updateLine(idx, { unitCode: e.target.value })} disabled={!canWrite} /></td>
                  <td data-label="SL" className={df.tdAmount}><Input type="number" value={String(line.quantity)} onChange={e => updateLine(idx, { quantity: Number(e.target.value) })} disabled={!canWrite} /></td>
                  <td data-label="Đơn giá" className={df.tdAmount}><Input type="number" value={String(line.unitPrice)} onChange={e => updateLine(idx, { unitPrice: Number(e.target.value) })} disabled={!canWrite} /></td>
                  <td data-label="Thành tiền" className={df.tdAmount} style={{ textAlign: 'right', paddingTop: 10 }}>{formatMoneyVnd(line.amount)}</td>
                  <td className={df.tdDel} data-label="">
                    <button type="button" className={df.btnDeleteLine} onClick={() => removeLine(idx)} title="Xóa dòng" disabled={!canWrite}>×</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <MaterialLinesGridActions
          canEdit={canWrite}
          onAddLine={addLine}
          onCopyLine={copyLine}
          linesCount={lines.length}
        />
      </div>
    </VoucherDocumentFormShell>
  );
};
export default DdmhFormPage;
